import React, { useState } from "react";
import { KycContext } from "../../context/KycContext";

function fakeMetamaskConnect() {
  // replace with real web3 logic later
  return Promise.resolve("0xUSER_WALLET_DEMO");
}

function UserDashboard() {
  const {
    requests,
    requestKyc,
    getKycForWallet,
    userUpdateKycRequest
  } = useKyc();

  const [newForm, setNewForm] = useState({
    fullName: "",
    walletAddress: "",
    country: "",
    note: ""
  });

  const [connectedWallet, setConnectedWallet] = useState("");
  const [lookedUpWallet, setLookedUpWallet] = useState("");
  const [loadingWallet, setLoadingWallet] = useState(false);

  const handleChangeNew = (e) => {
    const { name, value } = e.target;
    setNewForm((f) => ({ ...f, [name]: value }));
  };

  const submitNewKyc = (e) => {
    e.preventDefault();
    if (!newForm.fullName || !newForm.walletAddress) return;
    requestKyc(newForm);
    setNewForm({ fullName: "", walletAddress: "", country: "", note: "" });
  };

  const connectWallet = async () => {
    setLoadingWallet(true);
    const addr = await fakeMetamaskConnect();
    setConnectedWallet(addr);
    setLookedUpWallet(addr);
    setLoadingWallet(false);
  };

  const currentKyc = getKycForWallet(lookedUpWallet);

  const requestUpdate = () => {
    if (!lookedUpWallet) return;
    userUpdateKycRequest({ walletAddress: lookedUpWallet });
  };

  const myRequests = requests.filter(
    (r) =>
      r.walletAddress &&
      lookedUpWallet &&
      r.walletAddress.toLowerCase() === lookedUpWallet.toLowerCase()
  );

  return (
    <div className="page">
      <div className="page-header">
        <h1>User portal</h1>
        <span className="page-pill">Request & manage KYC</span>
      </div>

      <div className="grid">
        {/* LEFT: Request new KYC */}
        <div className="card">
          <h2>Request new KYC</h2>
          <p className="muted">
            Submit a fresh KYC request that a trusted issuer can review and
            approve.
          </p>

          <form onSubmit={submitNewKyc}>
            <label>
              Full name
              <input
                type="text"
                name="fullName"
                value={newForm.fullName}
                onChange={handleChangeNew}
                placeholder="Satoshi Nakamoto"
              />
            </label>

            <label>
              Wallet address
              <input
                type="text"
                name="walletAddress"
                value={newForm.walletAddress}
                onChange={handleChangeNew}
                placeholder="0x..."
              />
            </label>

            <label>
              Country
              <input
                type="text"
                name="country"
                value={newForm.country}
                onChange={handleChangeNew}
                placeholder="Country of residence"
              />
            </label>

            <label>
              Note for issuer (optional)
              <input
                type="text"
                name="note"
                value={newForm.note}
                onChange={handleChangeNew}
                placeholder="Any extra context for review"
              />
            </label>

            <button type="submit">Request KYC</button>
          </form>
        </div>

        {/* RIGHT: Status, expiry, update via wallet */}
        <div className="card">
          <h2>Your KYC status</h2>
          <p className="muted">
            Connect your wallet to see your credential, validation period, and
            request an update if it is expired.
          </p>

          <div className="row" style={{ marginBottom: 10 }}>
            <button type="button" onClick={connectWallet}>
              {connectedWallet ? "Reconnect wallet" : "Connect wallet"}
            </button>
            {loadingWallet && <span className="muted">Connecting…</span>}
            {connectedWallet && (
              <span className="muted">Connected: {connectedWallet}</span>
            )}
          </div>

          <label>
            Or check another wallet
            <input
              type="text"
              value={lookedUpWallet}
              onChange={(e) => setLookedUpWallet(e.target.value)}
              placeholder="0x..."
            />
          </label>

          {currentKyc ? (
            <>
              <div style={{ marginTop: 10 }}>
                <div className="row">
                  <span className="badge badge-ok">Valid credential</span>
                  <span className="muted">
                    Level {currentKyc.level} · Issuer {currentKyc.issuer}
                  </span>
                </div>
                <p className="muted" style={{ marginTop: 8 }}>
                  Expires on{" "}
                  <strong>
                    {new Date(currentKyc.expiry).toLocaleString()}
                  </strong>
                  .
                </p>
              </div>
              <button
                type="button"
                className="secondary"
                onClick={requestUpdate}
                style={{ marginTop: 10 }}
              >
                Request KYC update
              </button>
            </>
          ) : (
            <p className="muted" style={{ marginTop: 12 }}>
              No active KYC found for this wallet. You can submit a new KYC
              request on the left.
            </p>
          )}

          <h3 style={{ marginTop: 18, fontSize: "0.95rem" }}>Your requests</h3>
          {myRequests.length === 0 ? (
            <p className="muted">No requests yet for this wallet.</p>
          ) : (
            <table className="table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Type</th>
                  <th>Status</th>
                  <th>Updated</th>
                </tr>
              </thead>
              <tbody>
                {myRequests.map((r) => (
                  <tr key={r.id}>
                    <td>#{r.id}</td>
                    <td>{r.type === "update" ? "Update" : "New"}</td>
                    <td>
                      <span
                        className={`badge ${
                          r.status === "approved"
                            ? "badge-ok"
                            : r.status === "rejected"
                            ? "badge-bad"
                            : ""
                        }`}
                      >
                        {r.status}
                      </span>
                    </td>
                    <td>{new Date(r.updatedAt).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

export default UserDashboard;
